import java.util.*;

public class TrafficOptimizer {

    public static Map<String, List<String>> trafficOptimizer(Graph graph, String start, String end) {
        Map<String, Double> trafficDensity = graph.getTrafficDensity();
        Map<String, List<String>> optimizedPaths = new HashMap<>();
        PriorityQueue<Node> priorityQueue = new PriorityQueue<>(Comparator.comparingDouble(node -> node.cost));
        Map<String, Double> costSoFar = new HashMap<>();
        Map<String, String> cameFrom = new HashMap<>();

        priorityQueue.add(new Node(start, 0.0));
        costSoFar.put(start, 0.0);

        while (!priorityQueue.isEmpty()) {
            Node current = priorityQueue.poll();

            if (current.intersection.equals(end)) {
                break;
            }

            for (String neighbor : graph.getNeighbors(current.intersection)) {
                double newCost = costSoFar.get(current.intersection) + trafficDensity.get(neighbor);
                if (!costSoFar.containsKey(neighbor) || newCost < costSoFar.get(neighbor)) {
                    costSoFar.put(neighbor, newCost);
                    double priority = newCost;
                    priorityQueue.add(new Node(neighbor, priority));
                    cameFrom.put(neighbor, current.intersection);
                }
            }
        }

        List<String> path = new ArrayList<>();
        String current = end;
        while (!current.equals(start)) {
            path.add(current);
            current = cameFrom.get(current);
        }
        path.add(start);
        Collections.reverse(path);

        optimizedPaths.put("OptimizedPath", path);
        optimizedPaths.put("TotalCost", Collections.singletonList(String.valueOf(costSoFar.get(end))));

        return optimizedPaths;
    }

    static class Node {
        String intersection;
        double cost;

        Node(String intersection, double cost) {
            this.intersection = intersection;
            this.cost = cost;
        }
    }

    static class Graph {
        private Map<String, Map<String, Double>> adjacencyList = new HashMap<>();
        private Map<String, Double> trafficDensity = new HashMap<>();

        public void addIntersection(String intersection) {
            adjacencyList.putIfAbsent(intersection, new HashMap<>());
        }

        public void addRoad(String from, String to, double density) {
            adjacencyList.get(from).put(to, density);
            trafficDensity.put(to, density);
        }

        public Map<String, Double> getTrafficDensity() {
            return trafficDensity;
        }

        public Set<String> getNeighbors(String intersection) {
            return adjacencyList.getOrDefault(intersection, Collections.emptyMap()).keySet();
        }
    }
}
