pub fn calculate_stats(numbers: &[i32]) -> (i32, i32, f64) {
    if numbers.is_empty() {
        return (0, 0, 0.0);
    }

    let mut min = numbers[0];
    let mut max = numbers[0];
    let mut sum = 0i64;

    for &num in numbers {
        min = cmp::min(min, num);
        max = cmp::max(max, num);
        sum += num as i64;
    }

    let avg = sum as f64 / numbers.len() as f64;

    (min, max, avg)
}
