import java.util.*;

public class NetworkAnalyzer {
    public static List<Integer> analyzeNetworkConnectivity(Map<Integer, List<Integer>> graph) {
        List<Integer> criticalNodes = new ArrayList<>();
        if (graph == null || graph.isEmpty()) {
            return criticalNodes;
        }

        Set<Integer> nodes = new HashSet<>(graph.keySet());
        for (int node : nodes) {
            Map<Integer, List<Integer>> tempGraph = new HashMap<>();
            for (Map.Entry<Integer, List<Integer>> entry : graph.entrySet()) {
                if (entry.getKey() != node) {
                    List<Integer> edges = new ArrayList<>();
                    for (int neighbor : entry.getValue()) {
                        if (neighbor != node) {
                            edges.add(neighbor);
                        }
                    }
                    tempGraph.put(entry.getKey(), edges);
                }
            }

            if (isNetworkDisconnected(tempGraph)) {
                criticalNodes.add(node);
            }
        }

        return criticalNodes;
    }

    private static boolean isNetworkDisconnected(Map<Integer, List<Integer>> graph) {
        if (graph.isEmpty()) {
            return false;
        }

        Set<Integer> visited = new HashSet<>();
        Queue<Integer> queue = new LinkedList<>();
        Integer startNode = graph.keySet().iterator().next();
        queue.add(startNode);
        visited.add(startNode);

        while (!queue.isEmpty()) {
            int node = queue.poll();
            for (int neighbor : graph.getOrDefault(node, Collections.emptyList())) {
                if (!visited.contains(neighbor)) {
                    visited.add(neighbor);
                    queue.add(neighbor);
                }
            }
        }

        return visited.size() != graph.size();
    }
}
