        match action.action {
            ActionType::Allocate => {
                if self.allocated_gates.contains(&action.details.gate_id) {
                    Err(format!("Gate {} is already allocated", action.details.gate_id))
                } else {
                    self.allocated_gates.insert(action.details.gate_id.clone());
                    Ok(format!("Gate {} allocated successfully", action.details.gate_id))
