            ActionType::Deallocate => {
                if self.allocated_gates.contains(&action.details.gate_id) {
                    self.allocated_gates.remove(&action.details.gate_id);
                    Ok(format!("Gate {} deallocated successfully", action.details.gate_id))
                } else {
                    Err(format!("Gate {} is not allocated", action.details.gate_id))
                }
