            ActionType::Status => {
                if self.allocated_gates.contains(&action.details.gate_id) {
                    Ok(format!("Gate {} is allocated", action.details.gate_id))
                } else {
                    Ok(format!("Gate {} is not allocated", action.details.gate_id))
                }
