void manageAirportGates(const map<string, variant<string, int>>& action) {
    static map<int, string> gateAssignments;

    auto it = action.find("type");
    if (it == action.end()) {
        cerr << "Error: Action type not specified" << endl;
        return;
    }

    string actionType = get<string>(it->second);

    if (actionType == "assign") {
        auto flightIt = action.find("flight");
        auto gateIt = action.find("gate");
        if (flightIt == action.end() || gateIt == action.end()) {
            cerr << "Error: Missing flight or gate for assign action" << endl;
            return;
        }
        string flight = get<string>(flightIt->second);
        int gate = get<int>(gateIt->second);
        gateAssignments[gate] = flight;
    } 
    else if (actionType == "unassign") {
        auto gateIt = action.find("gate");
        if (gateIt == action.end()) {
            cerr << "Error: Missing gate for unassign action" << endl;
            return;
        }
        int gate = get<int>(gateIt->second);
        gateAssignments.erase(gate);
    } 
    else if (actionType == "query") {
        auto gateIt = action.find("gate");
        if (gateIt == action.end()) {
            cerr << "Error: Missing gate for query action" << endl;
            return;
        }
        int gate = get<int>(gateIt->second);
        auto assignment = gateAssignments.find(gate);
