#include <unordered_map>

struct PermissionNode {
    std::string name;
    std::vector<PermissionNode*> children;
    PermissionNode* parent;

    PermissionNode(const std::string& n, PermissionNode* p = nullptr) : name(n), parent(p) {}
};

class PermissionTree {
private:
    PermissionNode* root;
    std::unordered_map<std::string, PermissionNode*> permissionMap;

    PermissionNode* findNode(const std::string& name) {
        auto it = permissionMap.find(name);
        return (it != permissionMap.end()) ? it->second : nullptr;
    }

public:
    PermissionTree() : root(nullptr) {}

    void addPermission(const std::string& name, const std::string& parentName = "") {
        if (permissionMap.find(name) != permissionMap.end()) {
            return; // Permission already exists
        }

        if (parentName.empty()) {
            if (root != nullptr) {
                return; // Root already exists
            }
            root = new PermissionNode(name);
            permissionMap[name] = root;
        } else {
            PermissionNode* parent = findNode(parentName);
            if (parent == nullptr) {
                return; // Parent not found
            }
            PermissionNode* newNode = new PermissionNode(name, parent);
            parent->children.push_back(newNode);
            permissionMap[name] = newNode;
        }
    }

    void updatePermission(const std::string& oldName, const std::string& newName) {
        PermissionNode* node = findNode(oldName);
        if (node == nullptr) {
            return; // Node not found
        }
        node->name = newName;
        permissionMap.erase(oldName);
        permissionMap[newName] = node;
    }

    void removePermission(const std::string& name) {
        PermissionNode* node = findNode(name);
        if (node == nullptr) {
            return; // Node not found
        }

        if (node == root) {
            delete root;
            root = nullptr;
            permissionMap.clear();
            return;
        }

        PermissionNode* parent = node->parent;
        for (auto it = parent->children.begin(); it != parent->children.end(); ++it) {
            if (*it == node) {
                parent->children.erase(it);
                break;
            }
        }

        // Recursively delete all children
        std::vector<PermissionNode*> nodesToDelete;
        nodesToDelete.push_back(node);
        while (!nodesToDelete.empty()) {
            PermissionNode* current = nodesToDelete.back();
            nodesToDelete.pop_back();
            for (PermissionNode* child : current->children) {
                nodesToDelete.push_back(child);
            }
            permissionMap.erase(current->name);
            delete current;
        }
    }
};

void managePermissions(PermissionTree& tree, const std::string& operation, const std::string& permission, const std::string& parentPermission = "") {
    if (operation == "add") {
        tree.addPermission(permission, parentPermission);
    } else if (operation == "update") {
        tree.updatePermission(parentPermission, permission); // parentPermission is oldName, permission is newName
    } else if (operation == "remove") {
        tree.removePermission(permission);
    }
}
