fn process_grid_operations(matrix: Vec<Vec<i32>>, operations: Vec<String>) -> Vec<Vec<i32>> {
    let mut result = matrix.clone();
    for op in operations {
        match op.as_str() {
            "rotate" => {
                if result.is_empty() {
                    continue;
                }
                let rows = result.len();
                let cols = result[0].len();
                let mut rotated = vec![vec![0; rows]; cols];
                for i in 0..rows {
                    for j in 0..cols {
                        rotated[j][rows - 1 - i] = result[i][j];
                    }
                }
                result = rotated;
            }
            "flip" => {
                for row in result.iter_mut() {
                    row.reverse();
                }
            }
            "invert" => {
                for row in result.iter_mut() {
                    for val in row.iter_mut() {
                        *val = if *val == 0 { 1 } else { 0 };
                    }
                }
            }
            _ => {}
        }
    }
    result
