    subnetwork_count = 0

    def dfs(node):
        stack = [node]
        while stack:
            current = stack.pop()
            for neighbor in adjacency_list.get(current, []):
                if neighbor not in visited:
                    visited.add(neighbor)
                    stack.append(neighbor)

    for node in adjacency_list:
        if node not in visited:
            visited.add(node)
            dfs(node)
            subnetwork_count += 1

    return subnetwork_count
