                if let Some(parent) = find_node_mut(root, &parent_id) {
                    parent.children.push(node);
                }
            } else {
                root.children.push(node);
            }
            None
        }
        NetworkAction::UpdateNode { id, config } => {
            if let Some(node) = find_node_mut(root, &id) {
                node.config = config;
            }
            None
        }
        NetworkAction::RemoveNode { id } => {
            remove_node(root, &id)
        }
        NetworkAction::GetNode { id } => {
            find_node(root, &id).cloned()
        }
    }
}

fn find_node_mut(node: &mut NetworkNode, id: &str) -> Option<&mut NetworkNode> {
    if node.id == id {
        return Some(node);
    }
    for child in &mut node.children {
        if let Some(found) = find_node_mut(child, id) {
            return Some(found);
        }
    }
    None
}

fn find_node(node: &NetworkNode, id: &str) -> Option<&NetworkNode> {
    if node.id == id {
        return Some(node);
    }
    for child in &node.children {
        if let Some(found) = find_node(child, id) {
            return Some(found);
        }
    }
    None
}

fn remove_node(node: &mut NetworkNode, id: &str) -> Option<NetworkNode> {
    if let Some(index) = node.children.iter().position(|child| child.id == id) {
        return Some(node.children.remove(index));
    }
    for child in &mut node.children {
        if let Some(removed) = remove_node(child, id) {
            return Some(removed);
        }
    }
    None
}
