using namespace std;

vector<int> findShortestPath(const unordered_map<int, vector<pair<int, int>>>& graph, int start, int end) {
    unordered_map<int, int> distances;
    unordered_map<int, int> previous;
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

    for (const auto& node : graph) {
        distances[node.first] = INT_MAX;
    }
    distances[start] = 0;
    pq.push({0, start});

    while (!pq.empty()) {
        int current_node = pq.top().second;
        int current_distance = pq.top().first;
        pq.pop();

        if (current_distance > distances[current_node]) {
            continue;
        }

        for (const auto& neighbor : graph.at(current_node)) {
            int neighbor_node = neighbor.first;
            int neighbor_distance = neighbor.second;
            int new_distance = current_distance + neighbor_distance;

            if (new_distance < distances[neighbor_node]) {
                distances[neighbor_node] = new_distance;
                previous[neighbor_node] = current_node;
                pq.push({new_distance, neighbor_node});
            }
        }
    }

    vector<int> path;
    if (distances[end] == INT_MAX) {
        return path;
    }

    for (int at = end; at != start; at = previous[at]) {
        path.push_back(at);
    }
    path.push_back(start);
    reverse(path.begin(), path.end());

    return path;
}
